const body = $input.first().json.body || $input.first().json;

const user_id        = body.user_id        || null;
// Optional pre-passed fields from AI Config Builder
const config_id      = body.config_id      || null;
const operator_name  = body.operator_name  || null;
const operator_tone  = body.operator_tone  || null;
const recommended_tools = Array.isArray(body.recommended_tools) ? body.recommended_tools : null;
const primary_niche  = body.primary_niche  || null;

if (!user_id) throw new Error('Missing required field: user_id');

const has_ai_context = !!(operator_name && recommended_tools && primary_niche);

return [{
  json: {
    user_id,
    config_id,
    has_ai_context,
    prefilled_ai: { operator_name, operator_tone, recommended_tools, primary_niche },
    now: new Date().toISOString()
  }
}];

// Collect all three parallel fetches
const items = $input.all();
const origin = $('Parse & Validate').first().json;

if (!items || items.length < 3) {
  throw new Error(`Expected 3 parallel fetch results, got ${items?.length || 0}. Check Supabase connectivity.`);
}

// Each item comes in order of connection — profile, entitlements, credits
// Use safe extraction since order may vary
const findItem = (key) => items.find(i => i.json && (Array.isArray(i.json) ? i.json[0]?.[key] !== undefined : i.json[key] !== undefined));

// Profile
const profileRaw = items[0].json;
const profile = Array.isArray(profileRaw) ? profileRaw[0] : profileRaw;
if (!profile?.user_id) throw new Error(`No user_profiles record for user_id: ${origin.user_id}`);

// Entitlements
const entRaw = items[1].json;
const entitlements = Array.isArray(entRaw) ? entRaw[0] : entRaw;
if (!entitlements?.user_id) throw new Error(`No user_entitlements record for user_id: ${origin.user_id}`);

// Credits
const credRaw = items[2].json;
const credits = Array.isArray(credRaw) ? credRaw[0] : credRaw;

return [{
  json: {
    user_id:       origin.user_id,
    now:           origin.now,
    has_ai_context: origin.has_ai_context,
    prefilled_ai:  origin.prefilled_ai,
    config_id:     origin.config_id,
    profile,
    entitlements,
    credit_balance: credits?.unlimited ? 'unlimited' : (credits?.balance ?? 0)
  }
}];

// Use pre-passed AI context — no extra DB fetch
const d = $input.first().json;
const ai = d.prefilled_ai;

return [{
  json: {
    ...d,
    operator_name:     ai.operator_name,
    operator_tone:     ai.operator_tone || 'professional',
    recommended_tools: ai.recommended_tools || [],
    primary_niche:     ai.primary_niche,
    gtm_summary:       null  // not passed in pre-fill, will fallback below
  }
}];

const fetchResult = $input.first().json;
const origin = $('Merge Parallel Fetches').first().json;

const record = Array.isArray(fetchResult) ? fetchResult[0] : fetchResult;

// Graceful fallback if AI config not yet ready
const operator_name     = record?.operator_name     || `${origin.profile.business_name || 'My'} AI Operator`;
const operator_tone     = record?.operator_tone     || 'professional';
const recommended_tools = record?.recommended_tools || ['launchpad_tool_1', 'launchpad_tool_2'];
const primary_niche     = record?.primary_niche     || 'General Business Automation';
const gtm_summary       = record?.gtm_strategy_summary || null;

return [{
  json: {
    ...origin,
    operator_name,
    operator_tone,
    recommended_tools,
    primary_niche,
    gtm_summary
  }
}];

// Merge both AI context paths into unified shape
const items = $input.all();
if (!items || items.length === 0) throw new Error('No AI context data after merge');
return [items[0]];

const d = $input.first().json;

// ── 1. Filter recommended tools against actual entitlements ──
const ent = d.entitlements || {};
const allToolKeys = Array.from({length: 10}, (_, i) => `launchpad_tool_${i + 1}`);

const entitled_tools = allToolKeys.filter(key => ent[key] === true);
const recommended = Array.isArray(d.recommended_tools) ? d.recommended_tools : [];

// Keep AI-recommended tools that user actually has access to
// Fall back to first 2 entitled tools if none of the recommended are entitled
let active_tools = recommended.filter(t => entitled_tools.includes(t));
if (active_tools.length === 0) {
  active_tools = entitled_tools.slice(0, 2);
}

// ── 2. Nova OS systems user has access to ──
const nova_os_keys = [
  'nova_os_lead_capture',
  'nova_os_followup',
  'nova_os_booking',
  'nova_os_nurture',
  'nova_os_reporting',
  'nova_os_sales'
];
const active_nova_os = nova_os_keys.filter(k => ent[k] === true);

// ── 3. Generate quick_start_steps based on niche + active tools ──
const niche = (d.primary_niche || '').toLowerCase();
const plan_tier = (d.profile.plan_tier || 'free').toLowerCase();

// Tool display names
const toolLabels = {
  launchpad_tool_1:  'AI Lead Finder',
  launchpad_tool_2:  'Copy Generator',
  launchpad_tool_3:  'Offer Builder',
  launchpad_tool_4:  'Email Sequencer',
  launchpad_tool_5:  'Funnel Mapper',
  launchpad_tool_6:  'Competitor Analyst',
  launchpad_tool_7:  'Ad Creative Studio',
  launchpad_tool_8:  'VSL Script Writer',
  launchpad_tool_9:  'AI Sales Closer',
  launchpad_tool_10: 'Business Automator'
};

// Niche-aware quick start steps
const nicheStepMap = [
  { keywords: ['saas', 'software', 'tech'],
    steps: [
      { step: 1, title: 'Map your SaaS funnel', action: 'Run Funnel Mapper with your trial-to-paid flow', tool: 'launchpad_tool_5' },
      { step: 2, title: 'Generate onboarding emails', action: 'Use Email Sequencer to build a 5-part activation sequence', tool: 'launchpad_tool_4' },
      { step: 3, title: 'Analyse top competitors', action: 'Run Competitor Analyst on your top 3 rivals', tool: 'launchpad_tool_6' }
    ]
  },
  { keywords: ['agency', 'marketing', 'ads', 'creative'],
    steps: [
      { step: 1, title: 'Generate ad creatives', action: 'Use Ad Creative Studio to produce 5 scroll-stopping concepts', tool: 'launchpad_tool_7' },
      { step: 2, title: 'Build your offer', action: 'Run Offer Builder to craft your agency retainer package', tool: 'launchpad_tool_3' },
      { step: 3, title: 'Write case study copy', action: 'Use Copy Generator to turn your results into proof assets', tool: 'launchpad_tool_2' }
    ]
  },
  { keywords: ['ecom', 'ecommerce', 'store', 'product', 'retail'],
    steps: [
      { step: 1, title: 'Find high-intent buyers', action: 'Run AI Lead Finder for your target customer profile', tool: 'launchpad_tool_1' },
      { step: 2, title: 'Create product ad copy', action: 'Use Copy Generator for your top 3 products', tool: 'launchpad_tool_2' },
      { step: 3, title: 'Build abandoned cart sequence', action: 'Set up Email Sequencer with a 3-step recovery flow', tool: 'launchpad_tool_4' }
    ]
  },
  { keywords: ['coach', 'consulting', 'consultant', 'service'],
    steps: [
      { step: 1, title: 'Craft your signature offer', action: 'Run Offer Builder with your core transformation outcome', tool: 'launchpad_tool_3' },
      { step: 2, title: 'Write your VSL script', action: 'Use VSL Script Writer to build a 5-minute video sales letter', tool: 'launchpad_tool_8' },
      { step: 3, title: 'Automate lead outreach', action: 'Use AI Lead Finder to identify and pre-qualify ideal clients', tool: 'launchpad_tool_1' }
    ]
  }
];

// Find matching niche steps
let quick_start_steps = null;
for (const entry of nicheStepMap) {
  if (entry.keywords.some(kw => niche.includes(kw))) {
    quick_start_steps = entry.steps;
    break;
  }
}

// Generic fallback steps
if (!quick_start_steps) {
  quick_start_steps = [
    { step: 1, title: 'Generate compelling copy', action: 'Use Copy Generator to create your homepage headline and hero copy', tool: 'launchpad_tool_2' },
    { step: 2, title: 'Define your offer', action: 'Run Offer Builder to structure your core product or service offer', tool: 'launchpad_tool_3' },
    { step: 3, title: 'Build your outreach list', action: 'Use AI Lead Finder to identify your first 100 ideal prospects', tool: 'launchpad_tool_1' }
  ];
}

// Filter quick start steps to only include tools the user has access to
// If tool not entitled, keep step but mark it as 'upgrade_required'
quick_start_steps = quick_start_steps.map(s => ({
  ...s,
  entitled: entitled_tools.includes(s.tool) || active_tools.includes(s.tool),
  tool_label: toolLabels[s.tool] || s.tool
}));

// ── 4. Assemble final dashboard_data object ──
const dashboard_data = {
  user_id:            d.user_id,
  business_name:      d.profile.business_name || 'Your Business',
  email:              d.profile.email || '',
  plan_tier:          d.profile.plan_tier || 'free',
  operator_name:      d.operator_name,
  operator_tone:      d.operator_tone,
  primary_niche:      d.primary_niche,
  credit_balance:     d.credit_balance,
  active_tools,
  entitled_tools,
  active_nova_os,
  quick_start_steps,
  gtm_summary:        d.gtm_summary || 'Complete your AI profile to unlock your personalised go-to-market strategy.',
  ai_operator_access: ent.ai_operator_access === true,
  subagent_access:    ent.subagent_access === true,
  dashboard_version:  1,
  generated_at:       d.now
};

return [{
  json: {
    user_id: d.user_id,
    now:     d.now,
    dashboard_data
  }
}];

const items = $input.all();
const origin = $('Build Dashboard Data').first().json;

if (!items || items.length < 2) {
  throw new Error(`Expected 2 write results (upsert + patch), got ${items?.length || 0}`);
}

const upsertRaw = items[0].json;
const upserted  = Array.isArray(upsertRaw) ? upsertRaw[0] : upsertRaw;

return [{
  json: {
    user_id:        origin.user_id,
    now:            origin.now,
    dashboard_data: origin.dashboard_data,
    dashboard_id:   upserted?.id || null,
    writes_ok:      !!upserted?.user_id
  }
}];

const triggerResult = $input.first().json;
const origin = $('Merge Write Results').first().json;

const welcome_triggered = !triggerResult?.error;

return [{
  json: {
    ...origin,
    welcome_triggered
  }
}];
